using System.Linq; using System.Windows; using System.Management.Automation; using System.Management.Automation.Runspaces; namespace OrchestrationDesktop.Views { public partial class MainWindow : Window { private Runspace _rs; public MainWindow() { InitializeComponent(); Loaded += OnLoaded; BtnRunDialog.Click += (_, __) => new RunDialog().ShowDialog(); BtnListPrompts.Click += (_, __) => ListPrompts(); } private void OnLoaded(object s, RoutedEventArgs e) { _rs = RunspaceFactory.CreateRunspace(); _rs.Open(); using var ps = PowerShell.Create(); ps.Runspace = _rs; var repoRoot = System.IO.Path.GetFullPath(System.IO.Path.Combine(System.AppContext.BaseDirectory, "..","..","..","..")); var manifest = System.IO.Path.Combine(repoRoot, "modules", "PromptLibrary", "PromptLibrary.psd1"); ps.AddCommand("Import-Module").AddArgument(manifest).AddParameter("Force", true); ps.Invoke(); } private void ListPrompts() { using var ps = PowerShell.Create(); ps.Runspace = _rs; ps.AddScript("Get-Prompt | Select-Object id,title,tags | ConvertTo-Json -Depth 3"); var res = ps.Invoke(); var json = res.FirstOrDefault()?.ToString() ?? "[]"; MessageBox.Show(this, json, "Prompts (JSON)"); } } }